 39	
 40	type TopologySideBarContentProps = {
 41	  resource: K8sResourceCommon;
 42	};
 43	
 44	const AlertsTabComponent: React.FC<TopologySideBarContentProps> = ({
 45	  resource,
 46	}) => {
 47	  const defaultFilter = React.useMemo(
 48	    () => filterFactory(resource?.kind)(resource?.metadata?.name),
 49	    [resource?.kind, resource?.metadata?.name]
 50	  );
 51	  return <AlertsDetails alertsFilter={defaultFilter} />;
 52	};
