 54	type GenericTabComponentProps = {
 55	  resource: K8sResourceCommon;
 56	};
 57	
 58	const DetailsTabComponent: React.FC<GenericTabComponentProps> = ({
 59	  resource,
 60	}) => {
 61	  const kind = React.useMemo(() => resource?.kind, [resource?.kind]);
 62	  const Component = React.useMemo(() => {
 63	    switch (kind) {
 64	      case NodeModel.kind:
 65	        return NodeDetails;
 66	      case DeploymentModel.kind:
 67	        return DeploymentDetails;
 68	      case StorageClusterModel.kind:
 69	        return StorageClusterDetails;
 70	    }
 71	  }, [kind]);
 72	
 73	  return <Component resource={resource as any} />;
 74	};
