 76	const ResourceTabComponent: React.FC<GenericTabComponentProps> = ({
 77	  resource,
 78	}) => {
 79	  const { odfNamespace } = useODFNamespaceSelector();
 80	
 81	  const kind = React.useMemo(() => resource?.kind, [resource?.kind]);
 82	  const Component = React.useMemo(() => {
 83	    switch (kind) {
 84	      case NodeModel.kind:
 85	        return NodeResources;
 86	      case DeploymentModel.kind:
 87	        return DeploymentResources;
 88	      case StorageClusterModel.kind:
 89	        return StorageClusterResources;
 90	    }
 91	  }, [kind]);
 92	
 93	  return <Component resource={resource as any} odfNamespace={odfNamespace} />;
 94	};
 95	
 96	const ObserveTabComponent: React.FC<GenericTabComponentProps> = ({
 97	  resource,
 98	}) => {
 99	  const { odfNamespace } = useODFNamespaceSelector();
100	
101	  const kind = React.useMemo(() => resource?.kind, [resource?.kind]);
102	  const Component = React.useMemo(() => {
103	    switch (kind) {
104	      case NodeModel.kind:
105	        return NodeObserve;
106	      case DeploymentModel.kind:
107	        return DeploymentObserve;
108	      case StorageClusterModel.kind:
109	        return StorageClusterObserve;
110	    }
111	  }, [kind]);
112	
113	  return <Component resource={resource as any} odfNamespace={odfNamespace} />;
114	};
115	
116	const TopologySideBarContent: React.FC<TopologySideBarContentProps> = ({
117	  resource,
118	}) => {
119	  const [activeTab, setActiveTab] = React.useState(0);
120	  const { t } = useCustomTranslation();
121	
122	  const getResourceStatus =
123	    resource.kind === NodeModel.kind ? nodeStatus : null;
124	  const reference = getGVKofResource(resource);
125	  const [model, inFlight] = useK8sModel(reference);
126	
127	  const onSelect = React.useCallback(
128	    (_event, tabIndex) => {
129	      setActiveTab(tabIndex);
130	    },
131	    [setActiveTab]
132	  );
133	
134	  const title = <DetailsPageTitle resource={resource} resourceModel={model} />;
135	
136	  const { ref, height } = useAutoExpand();
137	
138	  return !inFlight ? (
139	    <div
140	      className="odf-topology__sidebar"
141	      ref={ref}
142	      style={{ height: `${height}px` }}
143	    >
144	      <PageHeading
145	        title={title}
146	        resource={resource}
147	        getResourceStatus={getResourceStatus}
148	        className="odf-topology-sidebar-heading"
149	      />
150	      <Tabs
151	        activeKey={activeTab}
152	        onSelect={onSelect}
153	        unmountOnExit
154	        className="odf-tabs"
155	      >
156	        <Tab
157	          className="odf-topology-sidebar__tab"
158	          eventKey={0}
159	          title={<TabTitleText>{t('Alerts')}</TabTitleText>}
160	        >
161	          <AlertsTabComponent resource={resource} />
162	        </Tab>
163	        <Tab
164	          className="odf-topology-sidebar__tab"
165	          eventKey={1}
166	          title={<TabTitleText>{t('Details')}</TabTitleText>}
167	        >
168	          <DetailsTabComponent resource={resource} />
169	        </Tab>
170	        <Tab
171	          className="odf-topology-sidebar__tab"
172	          eventKey={2}
173	          title={<TabTitleText>{t('Resources')}</TabTitleText>}
174	        >
175	          <ResourceTabComponent resource={resource} />
176	        </Tab>
177	        <Tab
178	          className="odf-topology-sidebar__tab"
179	          eventKey={3}
180	          title={<TabTitleText>{t('Observe')}</TabTitleText>}
181	        >
182	          <ObserveTabComponent resource={resource} />
183	        </Tab>
184	      </Tabs>
185	    </div>
186	  ) : (
187	    <LoadingBox />
188	  );
189	};
190	
191	export default TopologySideBarContent;

